function LFDTManager:LFDTManager()
end

function LFDTManager:StartRun()
    self:StopRun()
    self._loopTimer = LxTimer.LoopTimeCall(function()
        self:OnRun()
    end,0,false,-1)
end

function LFDTManager:StopRun()
    LxTimer.LoopTimeStop(self._loopTimer)
    self._loopTimer  = nil
end

function LFDTManager:ClearWhenExit()
    self:StopRun()


    self._moveType = LFastDTFsmConst.MT_NORMAL

    if self._unitViewMgr then
        self._unitViewMgr:Dispose()
        self._unitViewMgr = nil
    end

    if self._gridUnitViewMgr then
        self._gridUnitViewMgr:Dispose()
        self._gridUnitViewMgr = nil
    end

    if self._seqCom then
        self._seqCom:Destroy()
        self._seqCom = nil
    end

    if self._flightBubble then
        self._flightBubble:Destroy()
        self._flightBubble = nil
    end
end

function LFDTManager:OnRun()
    self:DoRunMoveStart()
    self:DoRunMovePath()
    if self._startExcFunc then
        if not self._delayStartFuncTime or self._delayStartFuncTime < 0 then
            local func = self._startExcFunc
            self._startExcFunc = nil
            func()
        end
        self._delayStartFuncTime = (self._delayStartFuncTime or 0) - Time.deltaTime
    end
end

function LFDTManager:DoRunMoveStart()
    if self._fsmState ~= LFastDTFsmConst.MOVESTART  then return end
    if not self._moveTime then
        if #self._movePosList > 0 then
            local runPosInfo = table.remove(self._movePosList,1)
            self._runPosInfo = runPosInfo
            local pos = runPosInfo.pos
            self._moveTime = self:GetMoveTime(pos)
            self:DoPlayerMoveTo(pos,self._moveTime,runPosInfo,#self._movePosList < 1)
            self._moveTime = self._moveTime + 0.1
        end
    end
    if self._moveTime then
        if self._moveTime < 0 then
            self._moveTime = nil
            self._beforePosInfo = self._runPosInfo
            if #self._movePosList < 1 then
                self:SetFSMNormalState()
                if self._runPosInfo then
                    self:ExecuteClick(self._runPosInfo.idx)
                    if LFastDTFsmConst.DOANI_GRID_STATE == 1 then
                        ---@type LFDTUnitView
                        local bunitView = self._runPosInfo.unitView
                        if bunitView then
                            bunitView:SetUnitTransVisiable(false)
                        end
                    end
                end
                self._runPosInfo = nil
                local moveFinishCb = self._moveFinishCb
                self._moveFinishCb = nil
                if moveFinishCb then
                    moveFinishCb()
                end
            end
        else
            self._moveTime = self._moveTime - Time.deltaTime
        end
    end
end

function LFDTManager:GetMoveTime(pos)
    --local speed = 1
    --local dis = Vector2.Distance(self:GetPlayerPosition(),pos)
    --return dis / speed
    --- 反馈表修改
    return gModelFastDreamTrip:GetGameMoveToTime()
end

function LFDTManager:DoPlayerMoveTo(pos,moveTime,runPosInfo,isEnd)
    if not self._playerUnitView then return end

    local playerTrans = self:GetPlayerUnitGridTrans()
    if not playerTrans then return end

    local isDire2 = gModelFastDreamTrip:CheckCurMapIsDice2()

    ---@type LFDTUnitView
    local unitView = runPosInfo.unitView

    local playerUnitView = self._playerUnitView
    local curPos = self:GetPlayerPosition()
    local bFilp = pos.x <= curPos.x
    playerUnitView:SetSpineFilp(bFilp)

    local halfTime = moveTime / 2
    local hideTime = halfTime / 4
    local doHideTime = halfTime + hideTime

    local isFlight = false
    local moveType = self._moveType
    local isNormal = moveType == LFastDTFsmConst.MT_NORMAL
    if not isNormal then
        self:SetFlightBubbleShow(true)

        local tempAniShowInfo = AniShowInfoMap[moveType]
        if tempAniShowInfo and not string.isempty(tempAniShowInfo.spineAniName) then
            isFlight = true
            playerUnitView:SetPlayerAni(tempAniShowInfo.spineAniName,tempAniShowInfo.isLoop)
        end
    end

    local seq = self._seqCom:CreateSeq("DoPlayerMove")
    if isFlight then
        seq:Insert(0,playerTrans:DOMove(pos,moveTime - 0.2))

        local isDown = pos.y > curPos.y
        local state
        if isDown then
            state = bFilp and LFastDTFsmConst.DICE_TOP_LEFT or LFastDTFsmConst.DICE_TOP_RIGHT
        else
            state = bFilp and LFastDTFsmConst.DICE_DOWN_LEFT or LFastDTFsmConst.DICE_DOWN_RIGHT
        end
        playerUnitView:SetOtherTargetShow(state)
        seq:InsertCallback(doHideTime,function()
            local beforeIndex = playerUnitView:GetUnitViewIndex()
            if beforeIndex then
                self:SetGridTagShowState(beforeIndex,false)
            end
            self:SetGridTagShowState(runPosInfo.idx,true)
        end)
    else
        if isDire2 then
            seq:Insert(0,playerTrans:DOMove(pos,moveTime - 0.2))

            playerUnitView:SetPlayerAni("run",true)
            local isDown = pos.y > curPos.y
            local state
            if isDown then
                state = bFilp and LFastDTFsmConst.DICE_TOP_LEFT or LFastDTFsmConst.DICE_TOP_RIGHT
            else
                state = bFilp and LFastDTFsmConst.DICE_DOWN_LEFT or LFastDTFsmConst.DICE_DOWN_RIGHT
            end
            playerUnitView:SetTargetShow(state)
            seq:InsertCallback(doHideTime,function()
                local beforeIndex = playerUnitView:GetUnitViewIndex()
                if beforeIndex then
                    self:SetGridTagShowState(beforeIndex,false)
                end
                self:SetGridTagShowState(runPosInfo.idx,true)
                if not isNormal then
                    gModelFastDreamTrip:TargetRewardShowEff(runPosInfo.idx,isEnd)
                end
            end)
            gModelFastDreamTrip:PlayDreamTripSound(307)
        else
            playerUnitView:SetPlayerAni("jump1",false)

            -- 跳跃
            gModelFastDreamTrip:PlayDreamTripSound(301)

            local recordY = pos.y
            local jumpY = recordY + gModelFastDreamTrip:GetGameJumpHeight()
            local curPosX = curPos.x
            local centerPosX = curPosX + (pos.x - curPosX) / 2

            self._mapCls:OnDragStart()

            local jump1Pos = Vector3(centerPosX,jumpY,pos.z)
            local centerTime = moveTime / 2
            seq:Insert(0,playerTrans:DOMove(jump1Pos,centerTime))

            --[[        seq:InsertCallback(0.1,function()
                        local beforeIndex = playerUnitView:GetUnitViewIndex()
                        if beforeIndex then
                            self:SetGridTagShowState(beforeIndex,false)
                        end
                    end)]]

            seq:InsertCallback(centerTime,function()
                playerUnitView:SetPlayerAni("jump2",false)
                if not isNormal then
                    gModelFastDreamTrip:TargetRewardShowEff(runPosInfo.idx,isEnd)
                end
            end)
            seq:Insert(centerTime,playerTrans:DOMove(pos,centerTime))

            seq:InsertCallback(moveTime,function()
                self:MoveCameraToPlayer(centerTime)
                self._mapCls:OnDragEnd()
            end)
        end
    end

    --- 反馈表修改，不需要隐藏，直接踩上去  LFastDTFsmConst.DOANI_GRID_STATE = 1
    if LFastDTFsmConst.DOANI_GRID_STATE == 0 then
        --- 隐藏踩中单位
        seq:InsertCallback(moveTime / 4,function()
            if self._beforePosInfo then
                ---@type LFDTUnitView
                local bunitView = self._beforePosInfo.unitView
                if bunitView then
                    bunitView:SetUnitTransVisiable(true)
                end
            end
            self._beforePosInfo = nil
            if unitView then
                unitView:SetUnitTransVisiable(false)
            end
        end)
    end

    seq:OnComplete(function()
        if not isNormal then
            local isCanMoveEnd = self._isFlightEnd
            local newMoveType
            if isCanMoveEnd and isEnd then
                newMoveType = LFastDTFsmConst.MT_FLIGHTEND
            else
                newMoveType = LFastDTFsmConst.MT_FLIGHTTING
            end

            if newMoveType == LFastDTFsmConst.MT_FLIGHTEND then
                self:SetFlightBubbleShow(false)
                newMoveType = LFastDTFsmConst.MT_NORMAL
            else
                for k,v in pairs(AniShowInfoMap) do
                    playerUnitView:SetUnitOtherEffectDpShow(v.effName,k == newMoveType)
                end
            end
            self._moveType = newMoveType
        end

        self._seqCom:DeleteSeq("DoPlayerMove")
        playerUnitView:SetPlayerAni("idle",true)
        printInfoNR2("梦境之旅:","runPosInfo.idx = " .. runPosInfo.idx)
        playerUnitView:SetTargetShow()

        if self._moveType == LFastDTFsmConst.MT_NORMAL then
            playerUnitView:SetOtherTargetShow()
        end

        playerUnitView:SetUnitViewIndex(runPosInfo.idx)
        if isEnd then
            self:SetGridTagShowState(runPosInfo.idx,true)
        end
    end)
    seq:PlayForward()
end

function LFDTManager:DoRunMovePath()
    if self._fsmState ~= LFastDTFsmConst.MOVEPATH then return end

    if #self._movePathList < 1 then return end

    local playerTrans = self:GetPlayerUnitGridTrans()
    if not playerTrans then return end

    local playerUnitView = self._playerUnitView
    local len = #self._movePathList
    local changeIdx = len - 1
    self._moveTime = 0
    local movePosTime = gModelFastDreamTrip:GetGameMoveToTime()
    local seq = self._seqCom:CreateSeq("DoPlayMovePath")

    local startAniName = "run"
    local isLoop = true
    local moveType = self._moveType
    local isInitNormal = moveType == LFastDTFsmConst.MT_NORMAL
    if not isInitNormal then
        self:SetFlightBubbleShow(true)
    end
    local isInitFS = moveType == LFastDTFsmConst.MT_FLIGHTSTART
    local isCanMoveEnd = self._isFlightEnd

    ---骚操作都按照配置走
    if AniShowInfoMap[moveType] then
        local tempAniShowInfo = AniShowInfoMap[moveType]
        startAniName = tempAniShowInfo.spineAniName
        isLoop = tempAniShowInfo.isLoop
    end
    playerUnitView:SetPlayerAni(startAniName,isLoop)
    local spineAniName
    local beforeIndex = playerUnitView:GetUnitViewIndex()
    local halfTime = movePosTime / 2
    local hideTime = halfTime / 4
    local doHideTime = halfTime + hideTime
    local beforeMoveType
    local curPos = self:GetPlayerPosition()
    for i,v in ipairs(self._movePathList) do
        local idx = v.idx
        local pos = v.pos
        local time = (i - 1) * movePosTime
        seq:Insert(time,playerTrans:DOMove(pos,movePosTime))

        local newPos = curPos

        local calcTime = i * movePosTime
        local bTime = calcTime - 0.1
        curPos = pos
        seq:InsertCallback(time,function()
            local bFilp = pos.x <= newPos.x
            playerUnitView:SetSpineFilp(bFilp)
            local state
            local isDown = pos.y > newPos.y
            if isDown then
                state = bFilp and LFastDTFsmConst.DICE_TOP_LEFT or LFastDTFsmConst.DICE_TOP_RIGHT
            else
                state = bFilp and LFastDTFsmConst.DICE_DOWN_LEFT or LFastDTFsmConst.DICE_DOWN_RIGHT
            end

            if not isInitNormal then
                local tempAniShowInfo = AniShowInfoMap[moveType]
                if tempAniShowInfo and not string.isempty(tempAniShowInfo.spineAniName) then
                    if spineAniName ~= tempAniShowInfo.spineAniName then
                        spineAniName = tempAniShowInfo.spineAniName
                        playerUnitView:SetPlayerAni(spineAniName,tempAniShowInfo.isLoop)
                    end
                end

                beforeMoveType = moveType
                if isInitFS then
                    if i >= changeIdx then
                        moveType = isCanMoveEnd and LFastDTFsmConst.MT_FLIGHTEND or LFastDTFsmConst.MT_FLIGHTTING
                    else
                        moveType = LFastDTFsmConst.MT_FLIGHTTING
                    end
                    isInitFS = false
                else
                    if i >= changeIdx then
                        moveType = isCanMoveEnd and LFastDTFsmConst.MT_FLIGHTEND or LFastDTFsmConst.MT_FLIGHTTING
                    else
                        moveType = LFastDTFsmConst.MT_FLIGHTTING
                    end
                end
                playerUnitView:SetOtherTargetShow(state)
            else
                playerUnitView:SetTargetShow(state)
            end
            gModelFastDreamTrip:PlayDreamTripSound(307)
        end)
        local newBefore = beforeIndex
        beforeIndex = idx
        seq:InsertCallback(calcTime - doHideTime,function()
            if newBefore then
                self:SetGridTagShowState(newBefore,false)
            end
            self:SetGridTagShowState(idx,true)
            if v.unitView then
                v.unitView:SetUnitTransVisiable(false)
            end
        end)
        local showEffTime = bTime - 0.5
        local greaterZero = showEffTime > 0
        if not greaterZero then
            showEffTime = bTime - 0.1
        end
        seq:InsertCallback(showEffTime,function()
            gModelFastDreamTrip:TargetRewardShowEff(idx,i == len)
        end)
        seq:InsertCallback(bTime,function()
            playerUnitView:SetUnitViewIndex(idx)
            if idx == len then return end
        end)


        --seq:Append(playerTrans:DOMove(v.pos,movePosTime))
        --seq:AppendCallback(function()
        --    gModelFastDreamTrip:TargetRewardShowEff(v.idx)
        --end)
    end

    local lastRunInfo = self._movePathList[len]
    seq:OnComplete(function ()
        self._seqCom:DeleteSeq("DoPlayMovePath")

        playerUnitView:SetTargetShow()

        if moveType == LFastDTFsmConst.MT_FLIGHTEND then
            self:SetFlightBubbleShow(false)
            --GF.ShowMessage(ccClientText(20809))
            moveType = LFastDTFsmConst.MT_NORMAL
        else
            for k,v in pairs(AniShowInfoMap) do
                playerUnitView:SetUnitOtherEffectDpShow(v.effName,k == moveType)
            end
        end
        self._moveType = moveType

        if moveType == LFastDTFsmConst.MT_NORMAL then
            playerUnitView:SetPlayerAni("idle",true)
            --- 仅需要正常的时候才需要把状态重置掉
            playerUnitView:SetOtherTargetShow()
        end

        local moveFinishCb = self._moveFinishCb
        self._moveFinishCb = nil
        if moveFinishCb then
            moveFinishCb()
        end

        if lastRunInfo then
            local idx = lastRunInfo.idx
            playerUnitView:SetUnitViewIndex(idx)

            if gModelFastDreamTrip:CheckIsExecute() then
                printInfoNR("==================== 自动触发")
                self:ExecuteClick(idx)
            end

            if LFastDTFsmConst.DOANI_GRID_STATE == 1 then
                ---@type LFDTUnitView
                local bunitView = lastRunInfo.unitView
                if bunitView then
                    bunitView:SetUnitTransVisiable(false)
                end
            end
            self:SetGridTagShowState(idx,true)
        end
        self:SetFSMNormalState()
    end)

    self._movePathList = {}

    seq:PlayForward()
end

function LFDTManager:Destroy()
    self:ClearWhenExit()
    LGpBaseMgr.Destroy(self)
end

---@param mapCls LFastDreamTripMap
function LFDTManager:InitFastDreamTrip(mapCls,params)
    self:InitDatas()
    self._mapCls = mapCls
    self._mapTrans = mapCls:GetMapTrans()
    self._params = params
    self:InitMgr()
    self:InitRootNode()
end

function LFDTManager:InitDatas()
    ---@type LFastDreamTripMap
    self._mapCls = nil

    self._mapTrans = nil

    --- 参数
    self._params = nil

    self._mapId = nil

    self._mapGameId = nil

    --- 格子加载完成个数
    self._gridLoadFinishNum = 0

    --- 需要加载的格子总数
    self._gridAllNum = 0

    ---@type number 当前加载完 Unit 个数
    self._unitLoadFinishNum = 0

    ---@type number 需要加载 Unit 个数
    self._unitAllNum = 0

    ---@type LFDTUnitViewMgr
    self._unitViewMgr = nil

    ---@type LFDTUnitView
    self._playerUnitView = nil

    ---@type LFDTGridUnitViewMgr
    self._gridUnitViewMgr = nil

    ---@type SequenceCom
    self._seqCom = SequenceCom:New()

    --- 循环计时器
    self._loopTimer = nil

    --- 每个格子停顿下
    self._movePosList = {}

    --- 直接通过路径移动到终点
    self._movePathList = {}

    --- 状态
    self._fsmState = LFastDTFsmConst.DEFAULT

    ---@type function 初始化完成后的延迟执行事件
    self._startExcFunc = nil
    self._delayStartFuncTime = 2

    ---@type function
    self._moveFinishCb = nil

    ---@type boolean 加载状态
    self._loadFinish = false

    self._moveType = LFastDTFsmConst.MT_NORMAL

    ---@type LFDTFlightBubble
    self._flightBubble = LFDTFlightBubble:New()
end

function LFDTManager:InitMgr()
    local mapTrans = self._mapTrans
    if CS.IsNullObject(mapTrans) then return end

    local layerRoot = CS.FindTrans(mapTrans,"LayerRoot")
    if not self._gridUnitViewMgr then
        local templateRoot= CS.FindTrans(layerRoot,"TemplateRoot")
        local template = CS.FindTrans(templateRoot,"GridTemplate")

        ---@type LFDTGridUnitViewMgr
        local gridUnitViewMgr = LFDTGridUnitViewMgr:New()
        gridUnitViewMgr:InitData(self,{
            templateRoot = templateRoot,
            template = template,
        })
        self._gridUnitViewMgr = gridUnitViewMgr
    end

    if not self._unitViewMgr then
        ---@type LFDTUnitViewMgr
        local unitViewMgr = LFDTUnitViewMgr:New()
        local LayerObject = CS.FindTrans(layerRoot,"LayerObject")
        local iconTemplate = CS.FindTrans(layerRoot,"TemplateRoot/EventTemplate")
        unitViewMgr:InitData(self,LayerObject,iconTemplate)
        self._unitViewMgr = unitViewMgr
    end
end

function LFDTManager:InitRootNode()
    local mapCls = self._mapCls
    if not mapCls then return end

    local mapTrans = self._mapTrans
    if CS.IsNullObject(mapTrans) then return end

    local params = self._params
    if not params then return end

    self._mapId = params.mapId
    self._mapGameId = params.mapGameId

    -- 地图id
    local themeCfg = gModelFastDreamTrip:GetMapRefByMapId(self._mapId)
    if not themeCfg then return end

    local LayerRoot = CS.FindTrans(mapTrans,"LayerRoot")
    local LayerBg = CS.FindTrans(LayerRoot,"LayerBg")
    local bg_1Trans = CS.FindTrans(LayerBg,"bg_1")
    self:SetSprite(bg_1Trans,themeCfg.pic,function()
        --- 地图背景加载完后再完成格子初始化
        self:InitGrid()
    end)
end

function LFDTManager:InitGrid()
    local mapCls = self._mapCls
    if not mapCls then return end

    local mapTrans = self._mapTrans
    if CS.IsNullObject(mapTrans) then return end

    local params = self._params
    if not params then return end

    local mapId = self._mapId
    if not mapId or  mapId < 1 then
        mapId = gModelFastDreamTrip:GetDreamTripMapId()
        self._mapId = mapId
    end

    -- 地图id
    local themeCfg = gModelFastDreamTrip:GetMapRefByMapId(mapId)
    if not themeCfg then
        LogError("not mapId GameTable.SailingMapRef = " .. mapId)
        return
    end

    local mapGameId = self._mapGameId
    if not mapGameId or mapGameId < 1 then
        mapGameId = gModelFastDreamTrip:GetDreamTripMapGameId()
        self._mapGameId = mapGameId
    end

    local mapRef = gModelFastDreamTrip:GetMapDreamTripRefByRefId(mapGameId)
    if not mapRef then
        LogError("not mapGameId GameTable.MapDreamTripRef = " .. mapGameId)
        return
    end


    self._fsmState = LFastDTFsmConst.LOADGRID

    local LayerRoot = CS.FindTrans(mapTrans,"LayerRoot")
    local GridRoot = CS.FindTrans(LayerRoot,"GridRoot")

    local gridUnitViewMgr = self._gridUnitViewMgr
    gridUnitViewMgr:SetParentRoot(GridRoot)

    local mapRefList = gModelFastDreamTrip:GetDreamTripMapListByMapId(mapId)
    if not mapRefList then
        mapRefList = {}
    end

    self._gridLoadFinishNum = 0
    self._gridAllNum = #mapRefList

    local recordErrStrs = {}
    local platformImgs = string.split(themeCfg.platform,";")
    for platform,platformRef in ipairs(mapRefList) do
        local ref = mapRef[platformRef.platformNum]
        if ref then
            gridUnitViewMgr:CreateGrid(ref,platformRef,themeCfg,platformImgs,function()
                self:UpdateGridLoadNum()
            end)
        else
            table.insert(recordErrStrs,"MapDreamTripRef 不存在的配置:" .. platformRef.platformNum)
            self:UpdateGridLoadNum()
        end
    end
    if #recordErrStrs > 0 then
        print("打印地块配置错误日志（检查 MapDreamTripRef 和 DreamTripPlatformRef）："..table.concat(recordErrStrs,","))
    end
end

function LFDTManager:UpdateGridLoadNum()
    self._gridLoadFinishNum = self._gridLoadFinishNum + 1
    if self._gridLoadFinishNum >= self._gridAllNum then
        --- 开始加载 Unit 单位
        self:LoadUnits()
    end
end

function LFDTManager:LoadUnits()
    self._fsmState = LFastDTFsmConst.LOADUNIT

    self._unitLoadFinishNum = 0
    self._unitAllNum = 0

    local params = self._params
    if not params then return end

    -- 地图id
    local themeCfg = gModelFastDreamTrip:GetMapRefByMapId(params.mapId)
    if not themeCfg then return end

    local unitDataMap = {}
    local gridInfos = gModelFastDreamTrip:GetDreamTripGridInfo()

    --- 默认为1，要加载 玩家角色模型
    local needLoadUnitNum = 1
    ---@param gridInfo StructDreamTripGrid
    for k,gridInfo in pairs(gridInfos) do
        if not gridInfo:CheckGridIsFinish() then
            unitDataMap[gridInfo.index] = gridInfo
            needLoadUnitNum = needLoadUnitNum + 1

        end
    end
    self._unitAllNum = needLoadUnitNum

    local loadCb = function()
        self:UpdateUnitLoadNum()
    end

    local curIndex = gModelFastDreamTrip:GetDreamTripIndex()
    local pos = self:GetGridUnitPosByIndex(curIndex)

    local unitViewMgr = self._unitViewMgr
    if pos then
        unitViewMgr:CreatePlayerObj(themeCfg,pos,loadCb)
    else
        if LOG_INFO_ENABLED then
            printInfoNR2("梦境之旅：","英雄处于不存在的位置：" .. curIndex)
        end
        self._unitAllNum = self._unitAllNum - 1
    end

    local recordErrStrs = {}
    ---@param gridInfo StructDreamTripGrid
    for index,gridInfo in pairs(unitDataMap) do
        local gridTrans = self:GetGridUnitByIndex(gridInfo.index)
        if gridTrans then
            unitViewMgr:CreateNPCObj(gridInfo,gridTrans,loadCb)
        else
            table.insert(recordErrStrs,"检查下配置，不存在的地块编号：" .. gridInfo.index)
            self:UpdateUnitLoadNum()
        end
    end
    if #recordErrStrs > 0 then
        print("打印地块数据错误日志："..table.concat(recordErrStrs,","))
    end
end

function LFDTManager:UpdateUnitLoadNum()
    self._unitLoadFinishNum = self._unitLoadFinishNum + 1
    if self._unitLoadFinishNum >= self._unitAllNum then
        local playerUnitView = self._unitViewMgr:GetPlayerUnit()
        if self._flightBubble then
            self._flightBubble:CreateBubble({
                followTran = playerUnitView:GetUnitTrans(),
                offset = Vector3(0,1,0)
            })

        end
        self._playerUnitView = playerUnitView
        self:DoUnitFinish()
    end
end

function LFDTManager:ErrorDispose()
    self._unitLoadFinishNum = self._unitAllNum
    self:UpdateUnitLoadNum()
end

function LFDTManager:DOGridShow()
    if gModelFastDreamTrip:CheckIsPlayAniMap() then
        self:NoShowInitGridAni()
    else
        self:PlayInitGridAni()
        gModelFastDreamTrip:ChangePlayAniMap()
    end
end

--- 播放格子动画
function LFDTManager:PlayInitGridAni()
    local seq = self._seqCom:CreateSeq("playGridAni")
    local scaleStartTime = 0.08
    local scaleBigTime = 0.4
    local scaleSmallTime = 0.2
    local scaleNormalTime = 0.1
    local scaleBig = 1.1
    local scaleSmall = 0.9
    local scale,startTime,time
    local gridAllNum = self._gridAllNum
    for i = 0,gridAllNum do
        local gridTrans = self:GetGridUnitByIndex(i)
        if not CS.IsNullObject(gridTrans) then
            CS.ShowObject(gridTrans,true)
            scale = gridTrans.localScale
            time = scaleStartTime * i
            startTime = time
            seq:Insert(time,gridTrans:DOScale(Vector3(scaleBig,scaleBig,scale.z),scaleBigTime)):SetEase(EaseOutQuad)
            time = time + scaleBigTime
            seq:Insert(time,gridTrans:DOScale(Vector3(scaleSmall,scaleSmall,scale.z),scaleSmallTime):SetEase(EaseOutQuad))
            seq:InsertCallback(time,function()
                self:SetMapCameraFollow(gridTrans,Vector3(0,0.5,0),1)
            end)
            --seq:InsertCallback(time,function()
            --    self:SetMapCameraFollow(gridTrans,Vector3(0,0.5,0),scaleBigTime)
            --end)
            time = time + scaleSmallTime
            seq:Insert(time,gridTrans:DOScale(Vector3(1,1,scale.z),scaleNormalTime):SetEase(EaseOutQuad))
        end
    end
    time = time + 1
    seq:InsertCallback(time,function()
        self:MoveCameraToPlayer()
    end)

    seq:OnComplete(function ()
        self._seqCom:DeleteSeq("playGridAni")
        self:DoInitMapFinish()
    end)
    seq:PlayForward()
end

--- 不播放格子动画
function LFDTManager:NoShowInitGridAni()
    self:MoveCameraToPlayer()
    local gridAllNum = self._gridAllNum
    for i = 0,gridAllNum do
        local gridTrans = self:GetGridUnitByIndex(i)
        if gridTrans then
            gridTrans.localScale = Vector3.one
        end
    end
    self:DoInitMapFinish()
end

function LFDTManager:DoInitMapFinish()
    self._loadFinish = true
    self:SetFSMNormalState()
    FireEvent(EventNames.ON_DREAMTRIP_GRIDANIEND)
    local index = gModelFastDreamTrip:GetDreamTripIndex()
    if gModelFastDreamTrip:CheckIsExecute() then
        ---@type LFDTUnitView
        local unitView = self:GetUnitViewByIndex(index)
        if unitView then
            unitView:SetUnitTransVisiable(false)
        end
        self._startExcFunc = function()
            if not gModelFastDreamTrip:CheckIsExecute() then return end
            gLGpManager:FindFastDreamTripGp():ExecuteClick(index)
        end
    end
    self:ShowBattleTargetShow()
    self:UpdatePlayerDire()
    self:InitShowFlightStatus()
    self:SetGridTagShowState(index,true)
    self:StartRun()
end

function LFDTManager:ShowBattleTargetShow()
    local playerUnitView = self._playerUnitView
    if not playerUnitView then return end
    local index = gModelFastDreamTrip:GetDreamTripIndex()
    local isCanBattle = gModelFastDreamTrip:CheckIndexEventBatlleCanPlay(index)
    playerUnitView:SetBattleTargetShow(isCanBattle)
end

function LFDTManager:UpdatePlayerDire()
    local playerUnitView = self._playerUnitView
    if not playerUnitView then return end
    local bFilp = gModelFastDreamTrip:GetCurPosFlip()
    playerUnitView:SetSpineFilp(bFilp)
end

function LFDTManager:InitShowFlightStatus()
    local isFlight = gModelFastDreamTrip:GetDreamTripIsFlight()
    self:SetFlightBubbleShow(isFlight)
    self._moveType = isFlight and LFastDTFsmConst.MT_FLIGHTTING or LFastDTFsmConst.MT_NORMAL
    if not isFlight then return end
    local playerUnitView = self._playerUnitView
    if not playerUnitView then return end
    local state = gModelFastDreamTrip:GetCurPosFlightDice()
    playerUnitView:SetOtherTargetShow(state)
end

function LFDTManager:SetFlightBubbleShow(bShow)
    if not self._flightBubble then return end
    self._flightBubble:ShowObject(bShow)
end

function LFDTManager:DoUnitFinish()
    self._fsmState = LFastDTFsmConst.LOADFINISH
    self:DOGridShow()
end

---@return Transform
function LFDTManager:GetGridUnitByIndex(gridIdx)
    return self._gridUnitViewMgr and self._gridUnitViewMgr:GetGridTransByGridIdx(gridIdx)
end

function LFDTManager:GetGridUnitPosByIndex(index)
    local gridTrans = self:GetGridUnitByIndex(index)
    if not gridTrans then return end
    return gridTrans.position
end

---@return LFDTUnitView
function LFDTManager:GetUnitViewByIndex(index)
    return self._unitViewMgr and self._unitViewMgr:GetNPCUnit(index)
end

function LFDTManager:SetSprite(trans,spriteRes,callback)
    local mapCls = self._mapCls
    if not mapCls then return end
    mapCls:SetSprite(trans,spriteRes,callback)
end

---@return LFastDreamTripMap
function LFDTManager:GetMap()
    return self._mapCls
end

function LFDTManager:CheckIsCanDragCamera()
    return self._fsmState == LFastDTFsmConst.NORMAL
end

function LFDTManager:CheckIsCanRoll()
    return self._fsmState == LFastDTFsmConst.NORMAL
end

function LFDTManager:GetPlayerUnitGridTrans()
    if not self._playerUnitView then return end
    return self._playerUnitView:GetUnitTrans()
end

---@return LDisplaySpine
function LFDTManager:GetPlayerUnitSpineDp()
    if not self._playerUnitView then return end
    return self._playerUnitView:GetUnitSpineDp()
end

function LFDTManager:GetPlayerPosition()
    local trans = self:GetPlayerUnitGridTrans()
    if not trans then return end
    return trans.position
end

function LFDTManager:GetPlayerPositionAndMoveFunc()
    local pos = self:GetPlayerPosition()
    local func = function()
        self:MoveCameraToPlayer()
    end
    return pos,func
end

function LFDTManager:MoveCameraToPlayer(moveTime)
    local trans = self:GetPlayerUnitGridTrans()
    if not trans then return end
    moveTime = moveTime or 0.1
    self:SetMapCameraFollow(trans,Vector3(0,0.5,0),moveTime)
end

function LFDTManager:SetMapCameraFollow(transform,offset,time)
    if not self._mapCls then return end
    self._mapCls:SetCameraFollow(transform,offset,time)
end

function LFDTManager:ExecuteClick(index)
    if not index then return end

    ---@type LFDTUnitView
    local unitView = self:GetUnitViewByIndex(index)
    if not unitView then return end

    ---@type StructDreamTripEventInfo
    local eventInfo = unitView:GetCurEventInfo()
    if not eventInfo then return end

    local curIndex = gModelFastDreamTrip:GetDreamTripIndex()
    if curIndex ~= eventInfo.index then
        --- 不是主角当前的位置，打开信息弹窗
        printInfoNR("不是主角当前的位置，打开信息弹窗,数据：" .. table.tostring(eventInfo))
        local params = {}
        params.openType = 1
        gModelFastDreamTrip:OpenEventTips(eventInfo,params)
        return
    end

    local serverData = gModelFastDreamTrip:GetDreamTripEventInfoByIdxAndId(eventInfo.index,eventInfo.eventId)
    if serverData and serverData:CheckIsFinishEvent() then return end

    if eventInfo:CheckIsFinishEvent() then return end

    gModelFastDreamTrip:OpenEventUI(eventInfo)
end

function LFDTManager:SetRollFsmState()
    self._fsmState = LFastDTFsmConst.ROLL
end

function LFDTManager:SetRollPlayer(config)
    local playerCurPos = self:GetPlayerPosition()
    local moveEndIdx = config.moveEndIdx
    local lastIndex = config.lastIndex + 1
    local transPosList = {}
    for i = lastIndex,moveEndIdx do
        local pos = self:GetGridUnitPosByIndex(i)
        pos.z = playerCurPos.z
        table.insert(transPosList,{
            pos = pos,
            idx = i,
            unitView = self:GetUnitViewByIndex(i)
        })
    end
    printInfoNR2("梦境之旅:",
            string.replace("moveEndIdx = #a1#,lastIndex = #a2#,列表长度 = #a3#",moveEndIdx,lastIndex,#transPosList)
    )
    if #transPosList < 1 then return end

    self._moveFinishCb = config.moveFinishCb
    self:DoRollMove(transPosList,config)
end

function LFDTManager:SetRollForkPlayer(config)
    local pointsList = config.pointsList or {}
    if #pointsList < 1 then return end
    local playerCurPos = self:GetPlayerPosition()
    local transPosList = {}
    for i,v in ipairs(pointsList) do
        local pos = self:GetGridUnitPosByIndex(v)
        pos.z = playerCurPos.z
        table.insert(transPosList,{
            pos = pos,
            idx = v,
            unitView = self:GetUnitViewByIndex(v)
        })
    end
    printInfoNR2("梦境之旅:",
            string.replace("岔路走 列表长度 = #a1#",#transPosList)
    )
    if #transPosList < 1 then return end
    self._moveFinishCb = config.moveFinishCb
    self:DoRollMove(transPosList,config)
end

function LFDTManager:DoRollMove(posList,config)
    local playerUnitView = self._playerUnitView
    local beforeIndex = playerUnitView:GetUnitViewIndex()
    if beforeIndex then
        self:SetGridTagShowState(beforeIndex,false)
    end

    self._fsmState = LFastDTFsmConst.MOVESTART

    self:CommonDisposeMoveType(config)

    self._movePosList = posList
    --self._movePathList = posList
end

function LFDTManager:SetFSMTPState()
    self._fsmState = LFastDTFsmConst.TP
end

function LFDTManager:SetFSMGetEffState()
    self._fsmState = LFastDTFsmConst.GETEFF
end

function LFDTManager:SetFSMNormalState()
    self._fsmState = LFastDTFsmConst.NORMAL
    self:ShowBattleTargetShow()
end

function LFDTManager:CheckIsFSMGetEffState()
    return self._fsmState == LFastDTFsmConst.GETEFF
end

function LFDTManager:CheckIsFSMMoveStartState()
    return self._fsmState == LFastDTFsmConst.MOVESTART
end

function LFDTManager:UpdateUnitViewGridData(config)
    if not self._unitViewMgr then return end
    self._unitViewMgr:UpdateUnitGridData(config)
end

function LFDTManager:GetPlayerUnitViewIndex()
    if not self._playerUnitView then return end
    return self._playerUnitView:GetUnitViewIndex()
end

function LFDTManager:SetRollPathMovePlayer(config)
    if not config then return end
    local playerCurPos = self:GetPlayerPosition()
    local moveEndIdx = config.moveEndIdx
    local lastIndex = config.lastIndex + 1
    local transPosList = {}
    for i = lastIndex,moveEndIdx do
        local pos = self:GetGridUnitPosByIndex(i)
        pos.z = playerCurPos.z
        table.insert(transPosList,{
            pos = pos,
            idx = i,
            unitView = self:GetUnitViewByIndex(i)
        })
    end
    if #transPosList < 1 then return end

    self._moveFinishCb = config.moveFinishCb
    self._fsmState = LFastDTFsmConst.MOVEPATH
    self:CommonDisposeMoveType(config)
    self._movePathList = transPosList
end

function LFDTManager:CommonDisposeMoveType(config)
    local moveType = LFastDTFsmConst.MT_NORMAL
    if self._moveType ~= LFastDTFsmConst.MT_NORMAL then
        moveType = self._moveType
    else
        if config.isFlight then
            moveType = LFastDTFsmConst.MT_FLIGHTSTART
        elseif config.isFlightEnd then
            moveType = LFastDTFsmConst.MT_FLIGHTSTART
        end
    end
    self._moveType = moveType
    self._isFlightEnd = config.isFlightEnd and true or false
end

function LFDTManager:SetRollPathListMovePlayer(config)
    if not config then return end
    local pointsList = config.pointsList
    if not pointsList or #pointsList < 1 then return end
    local playerCurPos = self:GetPlayerPosition()
    local transPosList = {}
    for i,v in ipairs(pointsList) do
        local pos = self:GetGridUnitPosByIndex(v)
        pos.z = playerCurPos.z
        table.insert(transPosList,{
            pos = pos,
            idx = v,
            unitView = self:GetUnitViewByIndex(v)
        })
    end
    if #transPosList < 1 then return end
    self._moveFinishCb = config.moveFinishCb
    self._fsmState = LFastDTFsmConst.MOVEPATH
    self._movePathList = transPosList
end

function LFDTManager:SetGridTagShowState(gridIndex,bShow)
    if not self._gridUnitViewMgr then return end
    self._gridUnitViewMgr:SetGridTagShowState(gridIndex,bShow)
end

--- 传送事件
function LFDTManager:DoPlayerTPAni(config)
    local boomIdx = config.boomIdx
    local boomPos = self:GetGridUnitPosByIndex(boomIdx)
    if not boomPos then
        self:SetFSMNormalState()
        return
    end

    local trans = self:GetPlayerUnitGridTrans()
    local playerSp = self:GetPlayerUnitSpineDp()
    local seq = self._seqCom:CreateSeq("DoPlayerTPAni")
    local startMoveTime = 1
    seq:Append(YXTween.TweenFloat(1, 0, startMoveTime, function(ival)
        playerSp:SetAlpha(ival)
    end):SetEase(DG.Tweening.Ease.OutCubic))
    seq:AppendInterval(0.5)
    seq:AppendCallback(function()
        local curIdx = config.curIdx
        if curIdx and curIdx > 0 then
            self:SetGridTagShowState(curIdx,false)
        end
        trans.position = boomPos
    end)
    seq:Append(YXTween.TweenFloat(0, 1, startMoveTime, function(ival)
        playerSp:SetAlpha(ival)
    end):SetEase(DG.Tweening.Ease.OutCubic))
    seq:AppendCallback(function()
        self:SetGridTagShowState(boomIdx,true)
    end)
    seq:AppendInterval(0.1)
    seq:OnComplete(function ()
        self._seqCom:DeleteSeq("DoPlayerTPAni")
        self:SetFSMNormalState()
        local boomEndIdx = config.boomEndIdx
        if boomEndIdx and boomEndIdx ~= boomIdx and boomEndIdx > 0 then
            self:SetRollPlayer({
                moveEndIdx = boomEndIdx,
                lastIndex = boomIdx,
            })
        else
            self:ExecuteClick(boomIdx)
        end
        local playerUnitView = self._playerUnitView
        if playerUnitView then
            playerUnitView:SetUnitViewIndex(boomEndIdx)
        end
    end)
    seq:PlayForward()
end

function LFDTManager:GetLoadFinishState()
    return self._loadFinish
end

function LFDTManager:GetMapId()
    return self._mapId
end

function LFDTManager:GetMapGameId()
    return self._mapGameId
end

function LFDTManager:CheckIsValidMap()
    local mapId = self:GetMapId()
    if mapId and mapId > 0 then
        local mapGameId = self:GetMapGameId()
        if mapGameId and mapGameId > 0 then
            return true
        end
    end
    return false
end

return LFDTManager